public class ShareReceiverActivity extends Activity {

    private TextView textView;
    private ImageView imageView;
    private TextView uriView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        ScrollView scrollView = new ScrollView(this);
        LinearLayout root = new LinearLayout(this);
        root.setOrientation(LinearLayout.VERTICAL);
        root.setPadding(32, 32, 32, 32);
        root.setGravity(Gravity.TOP);

        textView = new TextView(this);
        textView.setTextSize(18f);
        textView.setPadding(0, 0, 0, 24);

        imageView = new ImageView(this);
        imageView.setAdjustViewBounds(true);
        imageView.setScaleType(ImageView.ScaleType.FIT_CENTER);
        LinearLayout.LayoutParams imageParams = new LinearLayout.LayoutParams(
                ViewGroup.LayoutParams.MATCH_PARENT,
                ViewGroup.LayoutParams.WRAP_CONTENT
        );
        imageParams.bottomMargin = 24;
        imageView.setLayoutParams(imageParams);

        uriView = new TextView(this);
        uriView.setTextSize(14f);

        root.addView(textView);
        root.addView(imageView);
        root.addView(uriView);
        scrollView.addView(root);

        setContentView(scrollView);

        handleShareIntent(getIntent());
    }

    @Override
    protected void onNewIntent(Intent intent) {
        super.onNewIntent(intent);
        setIntent(intent);
        handleShareIntent(intent);
    }

    private void handleShareIntent(Intent intent) {
        if (intent == null) {
            showMessage("No shared content received.");
            return;
        }

        String action = intent.getAction();
        String type = intent.getType();

        if (Intent.ACTION_SEND.equals(action)) {
            if (type != null && type.startsWith("image/")) {
                handleSharedImage(intent);
            } else if ("text/plain".equals(type) || type == null) {
                handleSharedText(intent);
            } else {
                showMessage("Unsupported shared type: " + type);
            }
        } else if (Intent.ACTION_VIEW.equals(action)) {
            Uri data = intent.getData();
            if (data != null) {
                showMessage("Opened via VIEW intent:\n" + data.toString());
                uriView.setText("URI: " + data.toString());
            } else {
                showMessage("No data found in VIEW intent.");
            }
        } else {
            showMessage("Unsupported intent action: " + action);
        }
    }

    private void handleSharedText(Intent intent) {
        String sharedText = intent.getStringExtra(Intent.EXTRA_TEXT);
        String sharedSubject = intent.getStringExtra(Intent.EXTRA_SUBJECT);

        StringBuilder builder = new StringBuilder();
        if (sharedSubject != null) {
            builder.append("Subject: ").append(sharedSubject).append("\n\n");
        }
        if (sharedText != null) {
            builder.append(sharedText);
        }

        if (builder.length() == 0) {
            showMessage("No text content received.");
        } else {
            textView.setText(builder.toString());
            uriView.setText("");
            imageView.setImageDrawable(null);
        }
    }

    private void handleSharedImage(Intent intent) {
        Uri imageUri = intent.getParcelableExtra(Intent.EXTRA_STREAM);
        if (imageUri == null) {
            showMessage("No image URI received.");
            return;
        }

        try {
            ContentResolver resolver = getContentResolver();
            InputStream inputStream = resolver.openInputStream(imageUri);
            if (inputStream == null) {
                showMessage("Unable to open image stream.");
                return;
            }

            Bitmap bitmap = BitmapFactory.decodeStream(inputStream);
            inputStream.close();

            if (bitmap != null) {
                imageView.setImageBitmap(bitmap);
                textView.setText("Shared image received.");
                uriView.setText("URI: " + imageUri.toString() + getDisplayName(imageUri));
            } else {
                showMessage("Unable to decode image.");
            }
        } catch (IOException e) {
            showMessage("Error reading image: " + e.getMessage());
        }
    }

    private String getDisplayName(Uri uri) {
        Cursor cursor = null;
        try {
            cursor = getContentResolver().query(uri, null, null, null, null);
            if (cursor != null && cursor.moveToFirst()) {
                int nameIndex = cursor.getColumnIndex(OpenableColumns.DISPLAY_NAME);
                if (nameIndex >= 0) {
                    String name = cursor.getString(nameIndex);
                    return "\nFile: " + name;
                }
            }
        } catch (Exception ignored) {
        } finally {
            if (cursor != null) {
                cursor.close();
            }
        }
        return "";
    }

    private void showMessage(String message) {
        textView.setText(message);
        imageView.setImageDrawable(null);
        uriView.setText("");
        Toast.makeText(this, message, Toast.LENGTH_SHORT).show();
    }
}

